var d = tree.current_scene.save_load_dialog
var sel = d.saves_list.get_selected_items()
var fo = tree.root.get_viewport().gui_get_focus_owner()
return sel.size() == 1 and sel[0] == 1 and (fo is ItemList)

var d = tree.current_scene.save_load_dialog
var sel = d.saves_list.get_selected_items()
return sel.size() == 1 and sel[0] == 2 and (tree.root.get_viewport().gui_get_focus_owner() is ItemList)

var d = tree.current_scene.save_load_dialog
var fo = tree.root.get_viewport().gui_get_focus_owner()
return (not d.visible) and fo == tree.current_scene.load_button

for nm in ["scn_focus_A", "scn_focus_B", "scn_focus_C"]:
	SaveLoadManager.delete_save_file(nm)
return true
